104→  return (
105→    <StyledButton
106→      type="button"
107→      $large={large}
108→      $clear={clear}
109→      $round={round}
110→      $withIcon={!!icon}
111→      {...properties}
112→    >
113→      {icon && (
114→        <Icon color={clear ? color.primaryText : color.buttonText} size={iconSize} name={icon} />
115→      )}
116→      {icon && children && <Spacer />}
117→      {children}
118→    </StyledButton>
119→  )
120→}
