44→  ({ theme: { color, spacing } }) => css`
45→    color: ${color.error};
46→    margin-top: ${spacing.xxs};
47→    font-size: 12px;
48→    min-height: 16px;
49→  `
50→)
51→
52→type InputProps = {
53→  label?: string
54→  value?: any
55→  onChange?: (data: any) => void
56→  error?: string
57→} & DetailedHTMLProps<InputHTMLAttributes<HTMLInputElement>, HTMLInputElement>
58→
59→export const Input = ({ label = '', type = 'text', id, error, ...otherProps }: InputProps) => (
60→  <Container>
61→    {label && (
62→      <Body type="label" htmlFor={id}>
63→        {label}
64→      </Body>
65→    )}
66→    <input id={id} aria-label={label} type={type} {...otherProps} autoComplete="off" />
67→    <ErrorMessage>{error || ' '}</ErrorMessage>
68→  </Container>
